"use client";

import { useState } from "react";
import Link from "next/link";
import { WalletTabs } from "@/components/oli/WalletTabs";

type CardStatus = "live" | "guide" | "soon";

type AgentCard = {
  id: string;
  name: string;
  group: "assistant" | "dev" | "custom";
  status: CardStatus;
  blurb: string;
  // For 'live' clients: a one-line install command + a config snippet.
  install?: { command?: string; config?: string };
};

function buildCards(mcpUrl: string): AgentCard[] {
  return [
    // AI Assistants
    {
      id: "claude-ai",
      name: "Claude.ai",
      group: "assistant",
      status: "live",
      blurb:
        "Pro/Team. Settings → Connectors → Add. Paste the URL below; OAuth runs in browser.",
      install: { config: mcpUrl },
    },
    {
      id: "chatgpt",
      name: "ChatGPT",
      group: "assistant",
      status: "live",
      blurb:
        "Pro/Team. Settings → Connectors → Add. Paste the URL; OAuth runs in browser.",
      install: { config: mcpUrl },
    },
    {
      id: "gemini",
      name: "Gemini",
      group: "assistant",
      status: "live",
      blurb:
        "Pro. Settings → Extensions → Add. Paste the URL; OAuth runs in browser.",
      install: { config: mcpUrl },
    },

    // Dev Environments
    {
      id: "claude-code",
      name: "Claude Code",
      group: "dev",
      status: "live",
      blurb: "Native MCP. One command in your terminal.",
      install: {
        command: `claude mcp add pellet --transport http ${mcpUrl}`,
      },
    },
    {
      id: "cursor",
      name: "Cursor",
      group: "dev",
      status: "live",
      blurb: "Add to ~/.cursor/mcp.json:",
      install: {
        config: JSON.stringify(
          {
            mcpServers: {
              pellet: { url: mcpUrl },
            },
          },
          null,
          2,
        ),
      },
    },
    {
      id: "codex",
      name: "Codex / OpenCode",
      group: "dev",
      status: "live",
      blurb: "Same shape as Claude Code:",
      install: {
        command: `codex mcp add pellet --transport http ${mcpUrl}`,
      },
    },

    {
      id: "hermes",
      name: "Hermes",
      group: "dev",
      status: "live",
      blurb: "Add to your MCP config:",
      install: {
        config: JSON.stringify(
          {
            mcpServers: {
              pellet: { url: mcpUrl },
            },
          },
          null,
          2,
        ),
      },
    },

    // Custom backends
    {
      id: "custom",
      name: "Custom backend",
      group: "custom",
      status: "guide",
      blurb:
        "Build your own MCP client + register a webhook for user replies. See the docs.",
    },
  ];
}

function CopyButton({ value, label = "Copy" }: { value: string; label?: string }) {
  const [copied, setCopied] = useState(false);
  return (
    <button
      type="button"
      className="spec-onboard-copy"
      onClick={() => {
        navigator.clipboard.writeText(value).then(() => {
          setCopied(true);
          setTimeout(() => setCopied(false), 1400);
        });
      }}
      title="Copy to clipboard"
    >
      {copied ? (
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><polyline points="20 6 9 17 4 12" /></svg>
      ) : (
        <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect x="9" y="9" width="13" height="13" rx="2" /><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1" /></svg>
      )}
    </button>
  );
}

